const officeLat = 48.4618624, officeLon = 35.0466196;

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1))*Math.cos(toRad(lat2))*Math.sin(dLon/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

const shifts = $('Смены сегодня').all().map(i => i.json).filter(s => s && s.Id);
const employees = $('Все сотрудники').all().map(i => i.json).filter(e => e && e.Id);
const empById = {};
for (const e of employees) empById[String(e.Id)] = e;

const points = [];
const missing = [];
for (const s of shifts) {
  const emp = empById[String(s.Id)];
  if (!emp || !emp.Location) { missing.push(s.Name || s.Id); continue; }
  const m = String(emp.Location).match(/(-?\d+\.?\d*)\s*,\s*(-?\d+\.?\d*)/);
  if (!m) { missing.push(s.Name || s.Id); continue; }
  points.push({ name: s.Name, id: s.Id, lat: parseFloat(m[1]), lon: parseFloat(m[2]) });
}

let current = { lat: officeLat, lon: officeLon };
const remaining = [...points];
const route = [];
while (remaining.length) {
  let bestIdx = 0, bestDist = Infinity;
  for (let i = 0; i < remaining.length; i++) {
    const d = haversine(current.lat, current.lon, remaining[i].lat, remaining[i].lon);
    if (d < bestDist) { bestDist = d; bestIdx = i; }
  }
  const next = remaining.splice(bestIdx, 1)[0];
  route.push(next);
  current = next;
}

const groupSize = 4;
const groups = [];
for (let i = 0; i < route.length; i += groupSize) {
  groups.push(route.slice(i, i + groupSize));
}

let text = '🚕 Развозка на ' + $now.toFormat('dd.MM.yyyy') + '\n\n';
if (groups.length === 0) {
  text += 'Сегодня никто не отметился на смену.';
} else {
  groups.forEach((g, gi) => {
    text += 'Машина ' + (gi + 1) + ':\n';
    g.forEach((p, pi) => {
      const mapLink = 'https://maps.google.com/?q=' + p.lat + ',' + p.lon;
      text += (pi + 1) + '. ' + p.name + ' — ' + mapLink + '\n';
    });
    text += '\n';
  });
}
if (missing.length) {
  text += '⚠️ Без сохранённого домашнего адреса: ' + missing.join(', ');
}

const chatIdRow = employees.find(e => e.ChatId);
const chatId = chatIdRow ? chatIdRow.ChatId : '';

return [{ json: { text, chatId, groupsCount: groups.length } }];
